// Flag whether the CURRENT wind gusts at a position exceed a threshold.
// Delegates coord validation to the shared helper and reuses fetchWeather; the
// threshold comparison itself lives in the pure computeWindAlert function so
// this handler stays thin.
async function getWindAlert(c: any) {
  return functions.call('withValidatedCoords', c, async (lat: number, lon: number) => {
    // Reuse the shared weather fetch (Result pattern)
    const result = await functions.call('fetchWeather', lat, lon);

    // Map a fetch failure to a 500 with the underlying message
    if (!result.ok) {
      return c.json({ error: true, message: result.error.message }, 500);
    }

    const weatherData = result.data;

    // Resolve the effective threshold: optional per-request override wins,
    // else the tunable config default, else a hardcoded 25 kn fallback.
    const rawThreshold = c.req.query('threshold');
    const parsedThreshold = parseFloat(rawThreshold);
    const threshold = !isNaN(parsedThreshold)
      ? parsedThreshold
      : (config.get('WIND_GUST_ALERT_THRESHOLD_KNOTS') || 25);

    // Compute the alert from current conditions
    const alert = functions.call('computeWindAlert', weatherData.current, threshold);

    // Echo position/timezone alongside the alert fields for client display
    return c.json({
      latitude: weatherData.latitude,
      longitude: weatherData.longitude,
      timezone: weatherData.timezone,
      alert: alert.alert,
      gusts: alert.gusts,
      threshold: alert.threshold,
      message: alert.message
    });
  }, 'Failed to compute wind alert');
}
